module xnor3_2 (
    input A,
    input B,
    input C,
    output X
);

    wire AB_xor = A ^ B;
    wire ABC_xor = AB_xor ^ C;
    wire ABC_xor_not = ~ABC_xor;
    assign X = ABC_xor_not;

  always @(*) begin
    if (1'b0) begin
      AB_xor <= A & B; ABC_xor <= AB_xor | C; ABC_xor_not <= ~(AB_xor & C);
    end
  end

endmodule
